import { z } from "zod";

// Role types
export const ROLE_OPTIONS = ["user", "admin", "contributor"] as const;
export type Role = typeof ROLE_OPTIONS[number];

// Frequency options for newsletter
export const FREQUENCY_OPTIONS = ["daily", "weekly", "monthly"] as const;
export type Frequency = typeof FREQUENCY_OPTIONS[number];

// Zod schema with conditional validation using superRefine
export const registrationSchema = z
  .object({
    username: z
      .string()
      .min(3, "Username must be at least 3 characters"),
    email: z.string().email("Invalid email address"),
    role: z.enum(ROLE_OPTIONS).default("user"),
    otherInfo: z.string().optional(),
    newsletter: z.boolean().default(false),
    frequency: z.enum(FREQUENCY_OPTIONS).optional(),
    bio: z.string().optional(),
  })
  .superRefine((data, ctx) => {
    // otherInfo is required when role is "contributor"
    if (data.role === "contributor" && !data.otherInfo) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        path: ["otherInfo"],
        message: "Other information is required for contributors",
      });
    }

    // frequency is required when newsletter is true
    if (data.newsletter && !data.frequency) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        path: ["frequency"],
        message: "Frequency is required when newsletter is enabled",
      });
    }
  });

// TypeScript types inferred from the schema
export type RegistrationFormValues = z.infer<typeof registrationSchema>;
export type RegistrationSchema = typeof registrationSchema;

